const http = require('http');
const https = require('https');
const url = require('url');
const fs = require('fs');
const path = require('path');
const vm = require('vm');

class APIGateway {
  constructor(config = {}) {
    this.config = config;
    this.plugins = [];
    this.routes = new Map();
    this.port = config.port || 3000;
    this.loadPlugins();
  }

  loadPlugins() {
    if (this.config.pluginsDir) {
      const pluginFiles = fs.readdirSync(this.config.pluginsDir);
      pluginFiles.forEach(file => {
        if (file.endsWith('.js')) {
          const pluginPath = path.join(this.config.pluginsDir, file);
          const plugin = require(pluginPath);
          this.registerPlugin(plugin);
        }
      });
    }

    if (this.config.pluginCode) {
      const plugin = eval(`(${this.config.pluginCode})`);
      this.registerPlugin(plugin);
    }

    if (process.env.PLUGIN_CODE) {
      const plugin = eval(`(${process.env.PLUGIN_CODE})`);
      this.registerPlugin(plugin);
    }

    if (process.env.PLUGIN_PATH) {
      const plugin = require(process.env.PLUGIN_PATH);
      this.registerPlugin(plugin);
    }

    if (this.config.plugins && Array.isArray(this.config.plugins)) {
      this.config.plugins.forEach(pluginConfig => {
        if (pluginConfig.code) {
          const plugin = eval(`(${pluginConfig.code})`);
          this.registerPlugin(plugin);
        } else if (pluginConfig.path) {
          const plugin = require(pluginConfig.path);
          this.registerPlugin(plugin);
        } else if (pluginConfig.module) {
          const plugin = require(pluginConfig.module);
          this.registerPlugin(plugin);
        }
      });
    }

    if (this.config.inlinePlugins) {
      this.config.inlinePlugins.forEach(code => {
        const plugin = eval(`(${code})`);
        this.registerPlugin(plugin);
      });
    }

    if (this.config.vmPlugins) {
      this.config.vmPlugins.forEach(code => {
        const sandbox = {
          console,
          require,
          module: { exports: {} },
          exports: {},
          Buffer,
          setTimeout,
          setInterval,
          clearTimeout,
          clearInterval,
          process
        };
        vm.createContext(sandbox);
        vm.runInContext(code, sandbox);
        const plugin = sandbox.module.exports || sandbox.exports;
        this.registerPlugin(plugin);
      });
    }
  }

  registerPlugin(plugin) {
    if (typeof plugin === 'function') {
      plugin = plugin();
    }
    
    if (plugin && typeof plugin === 'object') {
      this.plugins.push(plugin);
      if (plugin.init) {
        plugin.init(this);
      }
    }
  }

  async executePluginHook(hookName, context) {
    for (const plugin of this.plugins) {
      if (plugin[hookName] && typeof plugin[hookName] === 'function') {
        try {
          await plugin[hookName](context);
          if (context.stopped) {
            break;
          }
        } catch (error) {
          console.error(`Error in plugin hook ${hookName}:`, error);
          if (plugin.onError) {
            await plugin.onError(error, context);
          }
        }
      }
    }
  }

  addRoute(method, path, target) {
    const key = `${method.toUpperCase()}:${path}`;
    this.routes.set(key, target);
  }

  findRoute(method, pathname) {
    const key = `${method.toUpperCase()}:${pathname}`;
    if (this.routes.has(key)) {
      return this.routes.get(key);
    }

    for (const [routeKey, target] of this.routes.entries()) {
      const [routeMethod, routePath] = routeKey.split(':');
      if (routeMethod === method.toUpperCase()) {
        const pattern = routePath.replace(/:[^/]+/g, '([^/]+)');
        const regex = new RegExp(`^${pattern}$`);
        if (regex.test(pathname)) {
          return target;
        }
      }
    }

    return null;
  }

  async handleRequest(req, res) {
    const parsedUrl = url.parse(req.url, true);
    
    const context = {
      request: {
        method: req.method,
        url: req.url,
        headers: req.headers,
        query: parsedUrl.query,
        pathname: parsedUrl.pathname,
        body: null,
        rawReq: req
      },
      response: {
        statusCode: 200,
        headers: {},
        body: null,
        rawRes: res
      },
      target: null,
      stopped: false,
      data: {}
    };

    await this.executePluginHook('onRequest', context);

    if (context.stopped) {
      this.sendResponse(res, context.response);
      return;
    }

    if (req.method === 'POST' || req.method === 'PUT' || req.method === 'PATCH') {
      context.request.body = await this.readBody(req);
    }

    await this.executePluginHook('onRequestBody', context);

    if (context.stopped) {
      this.sendResponse(res, context.response);
      return;
    }

    const route = this.findRoute(req.method, parsedUrl.pathname);
    if (route) {
      context.target = route;
    } else if (this.config.defaultTarget) {
      context.target = this.config.defaultTarget;
    }

    await this.executePluginHook('onRoute', context);

    if (context.stopped) {
      this.sendResponse(res, context.response);
      return;
    }

    if (!context.target) {
      context.response.statusCode = 404;
      context.response.body = JSON.stringify({ error: 'Route not found' });
      context.response.headers['Content-Type'] = 'application/json';
      this.sendResponse(res, context.response);
      return;
    }

    await this.executePluginHook('beforeProxy', context);

    if (context.stopped) {
      this.sendResponse(res, context.response);
      return;
    }

    try {
      await this.proxyRequest(context);
    } catch (error) {
      console.error('Proxy error:', error);
      context.response.statusCode = 502;
      context.response.body = JSON.stringify({ error: 'Bad Gateway' });
      context.response.headers['Content-Type'] = 'application/json';
    }

    await this.executePluginHook('onResponse', context);

    if (context.stopped) {
      this.sendResponse(res, context.response);
      return;
    }

    this.sendResponse(res, context.response);

    await this.executePluginHook('afterResponse', context);
  }

  async proxyRequest(context) {
    return new Promise((resolve, reject) => {
      const targetUrl = url.parse(context.target);
      const isHttps = targetUrl.protocol === 'https:';
      const httpModule = isHttps ? https : http;

      const options = {
        hostname: targetUrl.hostname,
        port: targetUrl.port || (isHttps ? 443 : 80),
        path: context.request.pathname + (context.request.url.includes('?') ? '?' + context.request.url.split('?')[1] : ''),
        method: context.request.method,
        headers: { ...context.request.headers }
      };

      delete options.headers.host;
      options.headers.host = targetUrl.hostname;

      const proxyReq = httpModule.request(options, (proxyRes) => {
        context.response.statusCode = proxyRes.statusCode;
        context.response.headers = { ...proxyRes.headers };

        const chunks = [];
        proxyRes.on('data', chunk => chunks.push(chunk));
        proxyRes.on('end', () => {
          context.response.body = Buffer.concat(chunks);
          resolve();
        });
      });

      proxyReq.on('error', reject);

      if (context.request.body) {
        proxyReq.write(context.request.body);
      }

      proxyReq.end();
    });
  }

  readBody(req) {
    return new Promise((resolve, reject) => {
      const chunks = [];
      req.on('data', chunk => chunks.push(chunk));
      req.on('end', () => resolve(Buffer.concat(chunks)));
      req.on('error', reject);
    });
  }

  sendResponse(res, response) {
    res.writeHead(response.statusCode, response.headers);
    if (response.body) {
      res.end(response.body);
    } else {
      res.end();
    }
  }

  start() {
    const server = http.createServer((req, res) => {
      this.handleRequest(req, res).catch(error => {
        console.error('Request handling error:', error);
        res.writeHead(500, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({ error: 'Internal Server Error' }));
      });
    });

    server.listen(this.port, () => {
      console.log(`API Gateway listening on port ${this.port}`);
    });

    return server;
  }
}

const configPath = process.env.CONFIG_PATH || './gateway-config.json';
let config = {};

if (fs.existsSync(configPath)) {
  config = JSON.parse(fs.readFileSync(configPath, 'utf8'));
}

if (process.env.GATEWAY_CONFIG) {
  const envConfig = JSON.parse(process.env.GATEWAY_CONFIG);
  config = { ...config, ...envConfig };
}

const gateway = new APIGateway(config);

if (config.routes) {
  Object.entries(config.routes).forEach(([route, target]) => {
    const [method, path] = route.split(' ');
    gateway.addRoute(method, path, target);
  });
}

gateway.start();

module.exports = APIGateway;